package main

import (
    "crypto/aes"
    "crypto/cipher"
    "crypto/rand"
    "io"
)

// Compliant: Using secure GCM mode
func encryptWithGCM(plaintext, key []byte) ([]byte, error) {
    // GOOD: AES with GCM mode provides both encryption and authentication
    block, err := aes.NewCipher(key)
    if err != nil {
        return nil, err
    }

    aead, err := cipher.NewGCM(block)
    if err != nil {
        return nil, err
    }

    // Generate random nonce
    nonce := make([]byte, aead.NonceSize())
    if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
        return nil, err
    }

    // GOOD: GCM handles padding automatically and provides authentication
    ciphertext := aead.Seal(nonce, nonce, plaintext, nil)
    return ciphertext, nil
}

// GOOD: Proper CBC with PKCS#7 padding
func encryptWithCBC(plaintext, key []byte) ([]byte, error) {
    // GOOD: AES-256 with CBC mode and proper padding
    block, err := aes.NewCipher(key)
    if err != nil {
        return nil, err
    }

    // Apply PKCS#7 padding
    plaintext = pkcs7Pad(plaintext, aes.BlockSize)

    // Generate random IV
    ciphertext := make([]byte, aes.BlockSize+len(plaintext))
    iv := ciphertext[:aes.BlockSize]
    if _, err := io.ReadFull(rand.Reader, iv); err != nil {
        return nil, err
    }

    mode := cipher.NewCBCEncrypter(block, iv)
    mode.CryptBlocks(ciphertext[aes.BlockSize:], plaintext)

    return ciphertext, nil
}

// GOOD: PKCS#7 padding implementation
func pkcs7Pad(data []byte, blockSize int) []byte {
    padding := blockSize - len(data)%blockSize
    padtext := bytes.Repeat([]byte{byte(padding)}, padding)
    return append(data, padtext...)
}

// GOOD: ChaCha20-Poly1305 as alternative AEAD
func encryptWithChaCha20Poly1305(plaintext, key []byte) ([]byte, error) {
    // GOOD: ChaCha20-Poly1305 is a secure AEAD cipher
    aead, err := chacha20poly1305.New(key)
    if err != nil {
        return nil, err
    }

    // Generate random nonce
    nonce := make([]byte, aead.NonceSize())
    if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
        return nil, err
    }

    ciphertext := aead.Seal(nonce, nonce, plaintext, nil)
    return ciphertext, nil
}

// GOOD: Decrypt with proper error handling
func decryptWithGCM(ciphertext, key []byte) ([]byte, error) {
    block, err := aes.NewCipher(key)
    if err != nil {
        return nil, err
    }

    aead, err := cipher.NewGCM(block)
    if err != nil {
        return nil, err
    }

    nonceSize := aead.NonceSize()
    if len(ciphertext) < nonceSize {
        return nil, errors.New("ciphertext too short")
    }

    nonce, ciphertext := ciphertext[:nonceSize], ciphertext[nonceSize:]
    return aead.Open(nil, nonce, ciphertext, nil)
}
